cd /app && cat > design.py << 'EOF'
import subprocess
seqs={}; name=None
for line in open('sequences.fasta'):
    line=line.strip()
    if not line: continue
    if line.startswith('>'): name=line[1:]; seqs[name]=''
    else: seqs[name]+=line.lower()
inp=seqs['input'];out=seqs['output'];egfp=seqs['egfp'];flag=seqs['flag'];snap=seqs['snap']
comp={'a':'t','t':'a','g':'c','c':'g'}
def rc(s): return ''.join(comp[c] for c in reversed(s))
def tm(s):
    r=subprocess.run(['oligotm','-tp','1','-sc','1','-mv','50','-dv','2','-n','0.8','-d','500',s.upper()],capture_output=True,text=True)
    return float(r.stdout.strip())

# overhangs (top strand, from output)
O1=out[210:214]; O2=out[924:928]; O3=out[1008:1012]; O4=out[1554:1558]
print('overhangs O1,O2,O3,O4=',O1,O2,O3,O4)
ohs=[O1,O2,O3,O4]
print('unique?',len(set(ohs))==4)
for o in ohs: print(o,'palindrome?',o==rc(o))
# also no overhang equals rc of another
for i in range(4):
    for j in range(4):
        if i!=j and ohs[i]==rc(ohs[j]): print('conflict',i,j)

# bodies (annealing templates, top strand 5'->3')
# egfp body top strand = egfp[4:714]
# flag body = flag[7:87]; snap body = snap[7:549]; input body = input[694:2727]+input[0:210]
bodies={
 'egfp': egfp[4:714],
 'flag': flag[7:87],
 'snap': snap[7:549],
 'input': inp[694:2727]+inp[0:210],
}
OL={'egfp':O1,'flag':O2,'snap':O3,'input':O4}
OR={'egfp':O2,'flag':O3,'snap':O4,'input':O1}
SPACER='tgcatc'
BSAI='ggtctc'
NN='a'   # 1 spacer nt between GGTCTC and overhang

def pick(anneal_full, tmin=58,tmax=72):
    # anneal_full is template strand 5'->3' for this primer's annealing (already oriented)
    best=None
    for L in range(15,37):
        if L>len(anneal_full): break
        s=anneal_full[:L]
        t=tm(s)
        if tmin<=t<=tmax:
            best=(L,s,t)
            # prefer near 65
            if abs(t-65)<3: break
    return best

results={}
for f in ['input','egfp','flag','snap']:
    body=bodies[f]
    fwd_anneal_full=body            # 5'->3'
    rev_anneal_full=rc(body)        # 5'->3' of reverse primer anneal region
    # choose lengths to get pair within 5C
    # gather candidates
    def cands(full):
        c=[]
        for L in range(15,37):
            if L>len(full):break
            s=full[:L]; t=tm(s)
            if 58<=t<=72: c.append((L,s,t))
        return c
    fc=cands(fwd_anneal_full); rc_=cands(rev_anneal_full)
    # pick pair minimizing |tm diff|, prefer mid-range
    best=None
    for lf,sf,tf in fc:
        for lr,sr,tr in rc_:
            if abs(tf-tr)<=5:
                score=abs(tf-tr)+abs(tf-65)*0.1+abs(tr-65)*0.1
                if best is None or score<best[0]:
                    best=(score,(lf,sf,tf),(lr,sr,tr))
    _,(lf,sf,tf),(lr,sr,tr)=best
    fwd=SPACER+BSAI+NN+OL[f]+sf
    rev=SPACER+BSAI+NN+rc(OR[f])+sr
    results[f]=(fwd,rev,tf,tr,len(sf),len(sr))
    print(f,'fwd Tm',round(tf,2),'len',len(sf),'rev Tm',round(tr,2),'len',len(sr),'diff',round(abs(tf-tr),2))

# write fasta
with open('primers.fasta','w') as fh:
    for f in ['input','egfp','flag','snap']:
        fwd,rev,tf,tr,_,_=results[f]
        fh.write('>%s_fwd\n%s\n>%s_rev\n%s\n'%(f,fwd.upper(),f,rev.upper()))
print('written')
EOF
